import { join, resolve } from "node:path";

import { pathExists, readTextFile, writeTextFile } from "./fs-utils";

export const TEAM_IMPL_LOG_FILE_NAME = "team-impl-log.md";

export interface EnsureTeamImplLogInput {
  specPackRoot: string;
  storyIds: string[];
}

export interface EnsureTeamImplLogResult {
  created: boolean;
  path: string;
  content: string;
}

function toReceiptStoryId(storyId: string): string {
  const numericPrefix = storyId.match(/^(\d+)/)?.[1];
  if (numericPrefix) {
    return `story-${numericPrefix.padStart(2, "0")}`;
  }

  return storyId.startsWith("story-") ? storyId : `story-${storyId}`;
}

function toReceiptTitle(storyId: string): string {
  const titleSource = storyId.replace(/^\d+-/, "");
  const words = titleSource
    .split("-")
    .filter(Boolean)
    .map((word) => word.toLowerCase());

  return words
    .map((word, index) => {
      if (index > 0 && ["a", "an", "and", "for", "in", "of", "on", "the", "to", "with"].includes(word)) {
        return word;
      }

      return word.charAt(0).toUpperCase() + word.slice(1);
    })
    .join(" ");
}

function renderStoryReceiptTemplate(storyIds: string[]): string {
  if (storyIds.length === 0) {
    return "- none yet";
  }

  const templateStoryId = storyIds[storyIds.length - 1];

  return [
    `### ${toReceiptStoryId(templateStoryId)}`,
    `- Title: ${toReceiptTitle(templateStoryId)}`,
    "- Implementor Evidence Ref: pending",
    "- Verifier Evidence Refs:",
    "  - pending",
    "- Gate Command: pending",
    "- Gate Result: pending",
    "- Dispositions:",
    "  - pending",
    "- Baseline Before Story: pending",
    "- Baseline After Story: pending",
    "- Open Risks:",
    "  - pending",
    "- User Acceptance: pending",
  ].join("\n");
}

export function renderTeamImplLogTemplate(input: EnsureTeamImplLogInput): string {
  const specPackRoot = resolve(input.specPackRoot);
  const storyLines =
    input.storyIds.length === 0
      ? "- none yet"
      : input.storyIds.map((storyId) => `- ${storyId}`).join("\n");

  return [
    "# Team Implementation Log",
    "",
    "## Run Overview",
    "- State: SETUP",
    `- Spec Pack Root: ${specPackRoot}`,
    "- Current Story: not-started",
    "- Current Phase: inspect",
    "",
    "## Run Configuration",
    "- Primary Harness: claude-code",
    "- Story Implementor: pending",
    "- Quick Fixer: pending",
    "- Story Verifier 1: pending",
    "- Story Verifier 2: pending",
    "- Self Review Passes: pending",
    "- Degraded Diversity: pending",
    "",
    "## Verification Gates",
    "- Story Gate: pending",
    "- Epic Gate: pending",
    "- Gate Discovery Source: pending",
    "",
    "## Story Sequence",
    storyLines,
    "",
    "## Current Continuation Handles",
    "- none",
    "",
    "## Story Receipts",
    renderStoryReceiptTemplate(input.storyIds),
    "",
    "## Cumulative Baselines",
    "- Baseline Before Current Story: pending",
    "- Expected After Current Story: pending",
    "- Latest Actual Total: pending",
    "",
    "## Cleanup / Epic Verification",
    "- Cleanup Artifact: pending",
    "- Cleanup Status: not-started",
    "- Epic Verification Status: not-started",
    "",
    "## Open Risks / Accepted Risks",
    "- none",
    "",
  ].join("\n");
}

export async function ensureTeamImplLog(
  input: EnsureTeamImplLogInput
): Promise<EnsureTeamImplLogResult> {
  const path = join(resolve(input.specPackRoot), TEAM_IMPL_LOG_FILE_NAME);

  if (await pathExists(path)) {
    return {
      created: false,
      path,
      content: await readTextFile(path),
    };
  }

  const content = renderTeamImplLogTemplate(input);
  await writeTextFile(path, content);

  return {
    created: true,
    path,
    content,
  };
}

import { describe, expect, test } from "bun:test";
import { join } from "node:path";

import { ensureTeamImplLog } from "../core/log-template";
import { createTempDir, writeTextFile } from "./test-helpers";

describe("team-impl log template", () => {
  test("TC-1.3a initializes a new log with the required recovery headings", async () => {
    const specPackRoot = await createTempDir("log-init");

    const result = await ensureTeamImplLog({
      specPackRoot,
      storyIds: ["00-foundation", "01-next"],
    });

    expect(result.created).toBe(true);
    expect(result.path).toBe(join(specPackRoot, "team-impl-log.md"));

    const content = await Bun.file(result.path).text();
    expect(content).toContain("# Team Implementation Log");
    expect(content).toContain("## Run Overview");
    expect(content).toContain("- State: SETUP");
    expect(content).toContain("## Run Configuration");
    expect(content).toContain("## Verification Gates");
    expect(content).toContain("## Story Sequence");
    expect(content).toContain("- 00-foundation");
    expect(content).toContain("- 01-next");
    expect(content).toContain("## Story Receipts");
    expect(content).toContain("## Cumulative Baselines");
    expect(content).toContain("## Cleanup / Epic Verification");
    expect(content).toContain("## Open Risks / Accepted Risks");
  });

  test("TC-1.3b preserves an existing log for resume instead of overwriting it", async () => {
    const specPackRoot = await createTempDir("log-resume");
    const existingPath = join(specPackRoot, "team-impl-log.md");
    await writeTextFile(existingPath, "# Existing Log\n\nresume marker\n");

    const result = await ensureTeamImplLog({
      specPackRoot,
      storyIds: ["00-foundation"],
    });

    expect(result.created).toBe(false);
    expect(await Bun.file(existingPath).text()).toBe(
      "# Existing Log\n\nresume marker\n"
    );
  });

  test("TC-6.1a keeps the receipt template aligned with the required acceptance evidence fields", async () => {
    const specPackRoot = await createTempDir("log-receipt");

    const result = await ensureTeamImplLog({
      specPackRoot,
      storyIds: ["06-story-acceptance-and-progression"],
    });

    expect(result.content).toContain("## Story Receipts");
    expect(result.content).toContain("### story-06");
    expect(result.content).toContain("- Title: Story Acceptance and Progression");
    expect(result.content).toContain("- Implementor Evidence Ref: pending");
    expect(result.content).toContain("- Verifier Evidence Refs:");
    expect(result.content).toContain("  - pending");
    expect(result.content).toContain("- Gate Result: pending");
    expect(result.content).toContain("- Dispositions:");
    expect(result.content).toContain("  - pending");
    expect(result.content).toContain("- Baseline Before Story: pending");
    expect(result.content).toContain("- Baseline After Story: pending");
    expect(result.content).toContain("- Open Risks:");
    expect(result.content).toContain("  - pending");
  });
});
